  text-transform: uppercase; margin-bottom: 0.35rem;
}
.sidebar-logo-title {
  font-family: 'Noto Serif KR', serif;
  font-size: 1rem; font-weight: 700;
  line-height: 1.3;
}
.sidebar-logo-title span { color: #C0392B; }

.sidebar-section {
  padding: 1rem 1.5rem 0.5rem;
  font-family: 'DM Mono', monospace;
  font-size: 0.58rem; letter-spacing: 0.15em;
  color: rgba(255,255,255,0.3); text-transform: uppercase;
}
.sidebar-nav { flex: 1; padding: 0 0.75rem; }
.sidebar-link {
  display: flex; align-items: center; gap: 0.6rem;
  padding: 0.5rem 0.75rem;
  border-radius: 6px;
  text-decoration: none;
  color: rgba(255,255,255,0.55);
  font-size: 0.82rem;
  margin-bottom: 0.1rem;
  transition: all 0.15s;
  cursor: pointer;
}
.sidebar-link:hover, .sidebar-link.active {
  color: #F7F5F0;
  background: rgba(255,255,255,0.08);
}
.sidebar-link.active { color: #E8A89E; }
.sidebar-link-num {
  font-family: 'DM Mono', monospace;
  font-size: 0.6rem; color: rgba(255,255,255,0.2);
  width: 16px; flex-shrink: 0;
}
.sidebar-timer {
  margin: 1rem 1.5rem;
  padding: 1rem;
  background: rgba(255,255,255,0.05);
  border-radius: 8px;
  border: 1px solid rgba(255,255,255,0.08);
}
.timer-label {
  font-family: 'DM Mono', monospace;
  font-size: 0.58rem; letter-spacing: 0.12em;
  color: rgba(255,255,255,0.3); margin-bottom: 0.35rem;
}
.timer-display {
  font-family: 'DM Mono', monospace;
  font-size: 1.6rem; font-weight: 500;
  color: #F7F5F0; letter-spacing: 0.05em;
}
.timer-btn {
  display: flex; gap: 0.4rem; margin-top: 0.6rem;
}
.timer-btn button {
  flex: 1; padding: 0.3rem;
  background: rgba(255,255,255,0.08);
  border: 1px solid rgba(255,255,255,0.12);
  border-radius: 4px;
  color: rgba(255,255,255,0.6);
  font-size: 0.72rem; cursor: pointer;
  transition: all 0.15s;
}
.timer-btn button:hover { background: rgba(255,255,255,0.15); color: white; }
.timer-btn button.running { color: #E8A89E; border-color: rgba(192,57,43,0.4); }

/* ── MAIN ── */
.main {
  margin-left: 240px;
  min-height: 100vh;
}

/* ── PAGE HEADER ── */
.page-header {
  padding: 4rem 3.5rem 3rem;
  background: var(--ink);
  color: #F7F5F0;
  position: relative; overflow: hidden;
}
.page-header::before {
  content: '';
  position: absolute; top: 0; right: 0;
  width: 400px; height: 100%;
  background: radial-gradient(ellipse at right center, rgba(192,57,43,0.15) 0%, transparent 60%);
  pointer-events: none;
}
.page-header-eyebrow {
  font-family: 'DM Mono', monospace;
  font-size: 0.65rem; letter-spacing: 0.15em;
  color: rgba(255,255,255,0.35); text-transform: uppercase;
  margin-bottom: 1rem;
}
.page-header h1 {
  font-family: 'Noto Serif KR', serif;
  font-size: clamp(2rem, 3.5vw, 2.8rem);
  font-weight: 700; line-height: 1.2;
  margin-bottom: 1rem;
}
.page-header h1 em { color: #C0392B; font-style: normal; }
.page-header-sub {
  font-size: 0.92rem; color: rgba(255,255,255,0.5);
  max-width: 600px; line-height: 1.8;
}
.header-meta {
  display: flex; gap: 2rem; margin-top: 2rem;
  flex-wrap: wrap;
}
.header-meta-chip {
  display: flex; flex-direction: column; gap: 0.2rem;
}
.header-meta-chip-label {
  font-family: 'DM Mono', monospace;
  font-size: 0.58rem; letter-spacing: 0.1em;
  color: rgba(255,255,255,0.25); text-transform: uppercase;
}
.header-meta-chip-val {
  font-size: 0.85rem; color: rgba(255,255,255,0.7);
}

/* ── CONTENT ── */
.content {
  padding: 0 3.5rem 5rem;
}

/* ── SECTION ── */
.guide-section {
  padding-top: 4rem;
  border-top: 1px solid var(--rule);
  margin-top: 4rem;
}
.guide-section:first-of-type { margin-top: 3rem; border-top: none; }

.section-eyebrow {
  display: flex; align-items: center; gap: 0.75rem;
  font-family: 'DM Mono', monospace;
  font-size: 0.62rem; letter-spacing: 0.14em;
  color: var(--ink4); text-transform: uppercase;
  margin-bottom: 0.85rem;
}
.section-eyebrow::before {
  content: '';
  display: block; width: 24px; height: 1px;
  background: var(--red);
}
.section-h2 {
  font-family: 'Noto Serif KR', serif;
  font-size: clamp(1.4rem, 2.5vw, 1.9rem);
  font-weight: 700; line-height: 1.3;
  margin-bottom: 0.5rem;
  letter-spacing: -0.02em;
}
.section-lead {
  font-size: 0.9rem; color: var(--ink3);
  max-width: 680px; line-height: 1.85;
  margin-bottom: 2.5rem;
}

/* ── STRATEGY BOX ── */
.strategy-overview {
  display: grid; grid-template-columns: repeat(3, 1fr);
  gap: 1px; background: var(--rule);
  border: 1px solid var(--rule); border-radius: 10px;
  overflow: hidden; margin-bottom: 3rem;
}
.strategy-card {
  background: var(--bg);
  padding: 1.75rem;
}
.strategy-icon { font-size: 1.4rem; margin-bottom: 0.75rem; }
.strategy-title { font-weight: 700; font-size: 0.95rem; margin-bottom: 0.5rem; }
.strategy-desc { font-size: 0.82rem; color: var(--ink3); line-height: 1.7; }

/* ── TIMELINE SCRIPT ── */
.script-timeline {
  position: relative;
  padding-left: 2.5rem;
}
.script-timeline::before {
  content: '';
  position: absolute; left: 0.6rem; top: 0; bottom: 0;
  width: 1px; background: var(--rule-dark);
}
.script-block {
  position: relative;
  margin-bottom: 2.5rem;
}
.script-block::before {
  content: '';
  position: absolute; left: -2.5rem;
  top: 0.7rem;
  width: 9px; height: 9px;
  border-radius: 50%;
  background: var(--bg);
  border: 2px solid var(--rule-dark);
}
.script-block.key::before { background: var(--red); border-color: var(--red); }
.script-block.anchor::before { background: var(--ink); border-color: var(--ink); }

.script-header {
  display: flex; align-items: center; gap: 1rem;
  margin-bottom: 0.85rem;
}
.script-time {
  font-family: 'DM Mono', monospace;
  font-size: 0.68rem; padding: 0.2rem 0.6rem;
  border-radius: 4px;
  background: var(--bg2); color: var(--ink3);
  border: 1px solid var(--rule-dark);
  white-space: nowrap;
}
.script-block.key .script-time { background: var(--red-light); color: var(--red); border-color: rgba(192,57,43,0.25); }
.script-slide-ref {
  font-family: 'DM Mono', monospace;
  font-size: 0.65rem; color: var(--ink4);
}
.script-title { font-weight: 700; font-size: 0.95rem; }

.script-body {
  background: white;
  border: 1px solid var(--rule-dark);
  border-radius: 8px;
  overflow: hidden;
}
.script-purpose {
  padding: 0.85rem 1.25rem;
  background: var(--bg2);
  border-bottom: 1px solid var(--rule);
  font-size: 0.78rem; color: var(--ink3);
  display: flex; align-items: center; gap: 0.5rem;
}
.script-purpose strong { color: var(--ink2); }

.script-content { padding: 1.25rem; }
.script-line {
  padding: 0.75rem 1rem;
  border-radius: 6px;
  margin-bottom: 0.5rem;
  font-size: 0.87rem;
  line-height: 1.75;
  position: relative;
}
.script-line.speak {
  background: #FFFDF8;
  border: 1px solid rgba(139,105,20,0.15);
  border-left: 3px solid var(--gold);
}
.script-line.speak::before {
  content: '💬';
  position: absolute; top: 0.65rem; right: 0.75rem;
  font-size: 0.7rem; opacity: 0.4;
}
.script-line.action {
  background: var(--teal-light);
  border: 1px solid rgba(26,107,90,0.15);
  font-size: 0.8rem; color: var(--teal);
  display: flex; align-items: flex-start; gap: 0.5rem;
}
.script-line.action::before { content: '→'; flex-shrink: 0; margin-top: 0.1rem; }
.script-line.warning {
  background: var(--red-mid);
  border: 1px solid rgba(192,57,43,0.2);
  font-size: 0.8rem; color: var(--red);
  display: flex; align-items: flex-start; gap: 0.5rem;
}
.script-line.warning::before { content: '⚠'; flex-shrink: 0; }
.script-line.tip {
  background: var(--blue-light);
  border: 1px solid rgba(26,58,107,0.15);
  font-size: 0.8rem; color: var(--blue);
  display: flex; align-items: flex-start; gap: 0.5rem;
}
.script-line.tip::before { content: '✦'; flex-shrink: 0; }

.script-key-phrase {
  margin: 1rem 1.25rem;
  padding: 0.85rem 1rem;
  background: var(--gold-light);
  border-radius: 6px;
  border-left: 3px solid var(--gold);
}
.script-key-phrase-label {
  font-family: 'DM Mono', monospace;
  font-size: 0.6rem; letter-spacing: 0.1em;
  color: var(--gold); text-transform: uppercase; margin-bottom: 0.3rem;
}
.script-key-phrase-text {
  font-family: 'Noto Serif KR', serif;
  font-size: 0.95rem; font-weight: 600;
  color: var(--ink); line-height: 1.5;
}

/* ── QnA ── */
.qna-list { display: flex; flex-direction: column; gap: 1rem; }
.qna-item {
  border: 1px solid var(--rule-dark);
  border-radius: 10px;
  overflow: hidden;
  background: white;
}
.qna-q {
  padding: 1rem 1.25rem;
  background: var(--bg2);
  cursor: pointer;
  display: flex; align-items: flex-start; justify-content: space-between; gap: 1rem;
  transition: background 0.15s;
  user-select: none;
}
.qna-q:hover { background: var(--bg3); }
.qna-q-badge {
  font-family: 'DM Mono', monospace;
  font-size: 0.6rem; padding: 0.15rem 0.5rem;
  border-radius: 100px; white-space: nowrap; flex-shrink: 0;
  margin-top: 0.1rem;
}
.badge-danger { background: var(--red-light); color: var(--red); }
.badge-caution { background: var(--gold-light); color: var(--gold); }
.badge-easy { background: var(--teal-light); color: var(--teal); }
.qna-q-text {
  font-weight: 600; font-size: 0.88rem; flex: 1; line-height: 1.5;
}
.qna-toggle {
  font-size: 0.8rem; color: var(--ink4);
  transition: transform 0.2s; flex-shrink: 0;
}
.qna-item.open .qna-toggle { transform: rotate(180deg); }
.qna-a { display: none; padding: 1.25rem; border-top: 1px solid var(--rule); }
.qna-item.open .qna-a { display: block; }
.qna-intent {
  font-family: 'DM Mono', monospace;
  font-size: 0.65rem; color: var(--ink4);
  margin-bottom: 0.75rem; display: flex; align-items: center; gap: 0.4rem;
}
.qna-intent::before { content: '질문 의도:'; color: var(--red); }
.qna-answer {
  font-size: 0.87rem; line-height: 1.8; color: var(--ink2);
  margin-bottom: 0.85rem;
}
.qna-key {
  padding: 0.75rem 1rem;
  background: var(--gold-light);
  border-left: 3px solid var(--gold);
  border-radius: 4px;
  font-size: 0.83rem; color: var(--ink);
  font-family: 'Noto Serif KR', serif;
}
.qna-key-label {
  font-family: 'DM Mono', monospace;
  font-size: 0.58rem; letter-spacing: 0.1em;
  color: var(--gold); margin-bottom: 0.25rem;
}
.qna-follow {
  margin-top: 0.75rem;
  padding: 0.6rem 0.85rem;
  background: var(--blue-light);
  border-radius: 4px;
  font-size: 0.78rem; color: var(--blue);
}
.qna-follow-label { font-weight: 700; margin-bottom: 0.2rem; }

/* ── PSYCHOLOGY CARDS ── */
.psych-grid {
  display: grid; grid-template-columns: repeat(2, 1fr);
  gap: 1.25rem; margin-bottom: 2rem;
}
.psych-card {
  background: white;
  border: 1px solid var(--rule-dark);
  border-radius: 10px;
  padding: 1.5rem;
}
.psych-card-header {
  display: flex; align-items: center; gap: 0.75rem;
  margin-bottom: 1rem;
}
.psych-icon {
  width: 40px; height: 40px;
  border-radius: 8px;
  display: flex; align-items: center; justify-content: center;
  font-size: 1.1rem; flex-shrink: 0;
}
.psych-card-title { font-weight: 700; font-size: 0.9rem; line-height: 1.3; }
.psych-card-sub { font-size: 0.72rem; color: var(--ink4); }
.psych-body { font-size: 0.83rem; color: var(--ink2); line-height: 1.75; }
.psych-tactics { margin-top: 0.85rem; display: flex; flex-direction: column; gap: 0.4rem; }
.psych-tactic {
  display: flex; gap: 0.5rem; align-items: flex-start;
  font-size: 0.8rem; color: var(--ink2); line-height: 1.55;
}
.psych-tactic::before { content: '·'; color: var(--red); flex-shrink: 0; }

/* ── CHECKLIST ── */
.checklist-section {
  background: white;
  border: 1px solid var(--rule-dark);
  border-radius: 10px;
  overflow: hidden;
}
.checklist-header {
  padding: 1rem 1.5rem;
  background: var(--bg2);
  border-bottom: 1px solid var(--rule);
  font-weight: 700; font-size: 0.9rem;
  display: flex; justify-content: space-between; align-items: center;
}
.checklist-progress {
  font-family: 'DM Mono', monospace;
  font-size: 0.7rem; color: var(--ink4);
}
.checklist-progress span { color: var(--red); }
.checklist-group { padding: 1rem 1.5rem; border-bottom: 1px solid var(--rule); }
.checklist-group:last-child { border-bottom: none; }
.checklist-group-label {
  font-family: 'DM Mono', monospace;
  font-size: 0.62rem; letter-spacing: 0.1em;
  color: var(--ink4); text-transform: uppercase;
  margin-bottom: 0.65rem;
}
.check-item {
  display: flex; align-items: flex-start; gap: 0.7rem;
  padding: 0.45rem 0; cursor: pointer;
}
.check-box {
  width: 18px; height: 18px;
  border: 1.5px solid var(--rule-dark);
  border-radius: 4px;
  display: flex; align-items: center; justify-content: center;
  flex-shrink: 0; margin-top: 0.1rem;
  transition: all 0.15s;
  background: white;
}
.check-item.done .check-box {
  background: var(--teal); border-color: var(--teal);
  color: white;
}
.check-item.done .check-box::after { content: '✓'; font-size: 0.7rem; }
.check-item.done .check-text {
  text-decoration: line-through; color: var(--ink4);
}
.check-text { font-size: 0.85rem; color: var(--ink2); line-height: 1.5; }

/* ── FLOW DIAGRAM ── */
.flow-diagram {
  display: flex; align-items: flex-start; gap: 0;
  background: white;
  border: 1px solid var(--rule-dark);
  border-radius: 10px;
  overflow: hidden; margin-bottom: 2rem;
}
.flow-node {
  flex: 1; padding: 1.5rem 1.25rem;
  border-right: 1px solid var(--rule);
  position: relative;
}
.flow-node:last-child { border-right: none; }
.flow-node::after {
  content: '→';
  position: absolute; right: -10px; top: 50%;
  transform: translateY(-50%);
  color: var(--ink4); font-size: 0.9rem; z-index: 1;
}
.flow-node:last-child::after { display: none; }
.flow-node-phase {
  font-family: 'DM Mono', monospace;
  font-size: 0.58rem; letter-spacing: 0.1em;
  color: var(--ink4); margin-bottom: 0.4rem;
}
.flow-node-title { font-weight: 700; font-size: 0.88rem; margin-bottom: 0.35rem; }
.flow-node-time {
  font-family: 'DM Mono', monospace;
  font-size: 0.65rem; color: var(--red);
  margin-bottom: 0.6rem;
}
.flow-node-items {
  display: flex; flex-direction: column; gap: 0.3rem;
}
.flow-node-item {
  font-size: 0.76rem; color: var(--ink3); line-height: 1.5;
  display: flex; gap: 0.3rem;
}
.flow-node-item::before { content: '·'; color: var(--ink4); flex-shrink: 0; }

/* ── CLOSING STRATEGY ── */
.close-grid {
  display: grid; grid-template-columns: 1fr 1fr;
  gap: 1.25rem;
}
.close-card {
  background: white;
  border: 1px solid var(--rule-dark);
  border-radius: 10px;
  padding: 1.5rem;
}
.close-card-label {
  font-family: 'DM Mono', monospace;
  font-size: 0.6rem; letter-spacing: 0.12em;
  color: var(--ink4); text-transform: uppercase;
  margin-bottom: 0.6rem;
}
.close-card-title { font-weight: 700; font-size: 0.9rem; margin-bottom: 0.75rem; }
.close-card-body { font-size: 0.83rem; color: var(--ink2); line-height: 1.75; }
.close-card.highlight {
  background: var(--ink);
  color: #F7F5F0;
  border-color: transparent;
}
.close-card.highlight .close-card-label { color: rgba(255,255,255,0.35); }
.close-card.highlight .close-card-body { color: rgba(255,255,255,0.7); }

/* ── KILLER LINE BOX ── */
.killer-box {
  background: var(--ink);
  color: #F7F5F0;
  border-radius: 12px;
  padding: 2.5rem;
  margin: 2.5rem 0;
  position: relative; overflow: hidden;
}
.killer-box::before {
  content: '';
  position: absolute; top: 0; right: 0;
  width: 300px; height: 100%;
  background: radial-gradient(ellipse at right, rgba(192,57,43,0.2) 0%, transparent 60%);
}
.killer-box-label {
  font-family: 'DM Mono', monospace;
  font-size: 0.62rem; letter-spacing: 0.15em;
  color: var(--red); text-transform: uppercase;
  margin-bottom: 1rem; display: flex; align-items: center; gap: 0.5rem;
}
.killer-box-label::after { content: ''; flex: 1; height: 1px; background: rgba(192,57,43,0.3); }
.killer-phrase {
  font-family: 'Noto Serif KR', serif;
  font-size: clamp(1.1rem, 2vw, 1.4rem);
  font-weight: 700; line-height: 1.5;
  margin-bottom: 0.5rem;
  color: #F7F5F0;
}
.killer-phrase em { color: #E8A89E; font-style: normal; }
.killer-sub {
  font-size: 0.82rem; color: rgba(255,255,255,0.45); line-height: 1.7;
}

/* ── TABLE ── */
.simple-table {
  width: 100%; border-collapse: collapse;
  font-size: 0.83rem; margin-bottom: 1.5rem;
}
.simple-table th {
  text-align: left;
  padding: 0.65rem 1rem;
  font-family: 'DM Mono', monospace;
  font-size: 0.62rem; letter-spacing: 0.08em;
  color: var(--ink4); text-transform: uppercase;
  background: var(--bg2);
  border-bottom: 1px solid var(--rule-dark);
}
.simple-table td {
  padding: 0.85rem 1rem;
  border-bottom: 1px solid var(--rule);
  color: var(--ink2); vertical-align: top; line-height: 1.6;
}
.simple-table tr:last-child td { border-bottom: none; }
.simple-table td:first-child { font-weight: 600; color: var(--ink); }

/* ── RESPONSIVE ── */
@media (max-width: 900px) {
  .sidebar { display: none; }
  .main { margin-left: 0; }
  .content { padding: 0 1.5rem 4rem; }
  .page-header { padding: 2rem 1.5rem; }
  .strategy-overview { grid-template-columns: 1fr; }
  .psych-grid, .close-grid { grid-template-columns: 1fr; }
  .flow-diagram { flex-direction: column; }
  .flow-node::after { display: none; }
  .flow-node { border-right: none; border-bottom: 1px solid var(--rule); }
}

@keyframes fadeUp {
  from { opacity: 0; transform: translateY(12px); }
  to { opacity: 1; transform: translateY(0); }
}
.guide-section { animation: fadeUp 0.4s ease both; }
</style>
</head>
<body>

