<script>
// ── QnA toggle ──
function toggleQna(el) {
  const item = el.parentElement;
  item.classList.toggle('open');
}

// ── Checklist ──
function toggleCheck(el) {
  el.classList.toggle('done');
  const total = document.querySelectorAll('.check-item').length;
  const done = document.querySelectorAll('.check-item.done').length;
  document.getElementById('checkCount').textContent = done;
}

// ── Timer ──
let seconds = 0, interval = null, running = false;
function toggleTimer() {
  if (running) {
    clearInterval(interval);
    running = false;
    document.getElementById('timerStart').textContent = '재개';
    document.getElementById('timerStart').classList.remove('running');
  } else {
    interval = setInterval(() => {
      seconds++;
      const m = String(Math.floor(seconds/60)).padStart(2,'0');
      const s = String(seconds%60).padStart(2,'0');
      document.getElementById('timerDisplay').textContent = `${m}:${s}`;
      // Color warning
      const display = document.getElementById('timerDisplay');
      if (seconds > 1680) display.style.color = '#C0392B'; // > 28min
      else if (seconds > 1440) display.style.color = '#E8A89E'; // > 24min
      else display.style.color = '#F7F5F0';
    }, 1000);
    running = true;
    document.getElementById('timerStart').textContent = '일시정지';
    document.getElementById('timerStart').classList.add('running');
  }
}
function resetTimer() {
  clearInterval(interval);
  running = false;
  seconds = 0;
  document.getElementById('timerDisplay').textContent = '00:00';
  document.getElementById('timerDisplay').style.color = '#F7F5F0';
  document.getElementById('timerStart').textContent = '시작';
  document.getElementById('timerStart').classList.remove('running');
}

// ── Active nav ──
const sections = document.querySelectorAll('.guide-section');
const links = document.querySelectorAll('.sidebar-link');
window.addEventListener('scroll', () => {
  let current = '';
  sections.forEach(s => { if(window.scrollY >= s.offsetTop - 120) current = s.id; });
  links.forEach(l => {
    l.classList.toggle('active', l.getAttribute('href') === '#' + current);
  });
});
</script>
