  text-transform: uppercase; margin-bottom: 1.25rem;
  display: flex; align-items: center; gap: 0.6rem;
}
.hero-eye::before { content: ''; width: 20px; height: 1px; background: var(--red); }
.hero h1 {
  font-family: var(--serif);
  font-size: clamp(1.8rem, 3vw, 2.6rem);
  font-weight: 700; color: #F4F3EF;
  line-height: 1.25; letter-spacing: -0.02em;
  margin-bottom: 1rem;
}
.hero h1 em { color: #D47A72; font-style: normal; }
.hero-sub {
  font-size: 0.88rem; color: rgba(255,255,255,0.42);
  max-width: 560px; line-height: 1.85; margin-bottom: 2.25rem;
}
.hero-chips {
  display: flex; gap: 1.5rem; flex-wrap: wrap;
}
.hero-chip { display: flex; flex-direction: column; gap: 0.15rem; }
.hero-chip-lbl {
  font-family: var(--mono); font-size: 0.56rem;
  letter-spacing: 0.1em; color: rgba(255,255,255,0.22);
  text-transform: uppercase;
}
.hero-chip-val { font-size: 0.82rem; color: rgba(255,255,255,0.6); }

/* ── BODY ── */
.body { padding: 0 3.5rem 6rem; }

/* ── SECTION ── */
.sec {
  padding-top: 3.5rem;
  border-top: 1px solid var(--rule);
  margin-top: 3.5rem;
}
.sec:first-of-type { margin-top: 3rem; border-top: none; }

.sec-eye {
  font-family: var(--mono); font-size: 0.6rem;
  letter-spacing: 0.13em; color: var(--ink4);
  text-transform: uppercase; margin-bottom: 0.7rem;
  display: flex; align-items: center; gap: 0.6rem;
}
.sec-eye::before { content: ''; width: 18px; height: 1px; background: var(--red); }
.sec-h2 {
  font-family: var(--serif);
  font-size: clamp(1.3rem, 2.2vw, 1.75rem);
  font-weight: 700; line-height: 1.3;
  letter-spacing: -0.02em; margin-bottom: 0.5rem;
}
.sec-lead {
  font-size: 0.88rem; color: var(--ink3);
  max-width: 660px; line-height: 1.9;
  margin-bottom: 2.25rem;
}

/* ── PHILOSOPHY BANNER ── */
.phil-banner {
  background: var(--ink);
  border-radius: 10px;
  padding: 2rem 2.25rem;
  margin-bottom: 2rem;
  position: relative; overflow: hidden;
}
.phil-banner::before {
  content: '';
  position: absolute; top: 0; right: 0;
  width: 250px; height: 100%;
  background: radial-gradient(ellipse at right, rgba(181,37,28,0.18) 0%, transparent 60%);
}
.phil-banner-lbl {
  font-family: var(--mono); font-size: 0.58rem;
  letter-spacing: 0.12em; color: var(--red);
  text-transform: uppercase; margin-bottom: 0.75rem;
}
.phil-banner-text {
  font-family: var(--serif);
  font-size: 1.05rem; font-weight: 600;
  color: #F4F3EF; line-height: 1.65;
}
.phil-banner-text em { color: #D47A72; font-style: normal; }
.phil-banner-sub {
  margin-top: 0.65rem;
  font-size: 0.8rem; color: rgba(255,255,255,0.38);
  line-height: 1.7;
}

/* ── NARRATIVE ARC ── */
.arc {
  display: flex; gap: 0; margin-bottom: 2.25rem;
  background: var(--white);
  border: 1px solid var(--rule2); border-radius: 9px;
  overflow: hidden;
}
.arc-node {
  flex: 1; padding: 1.25rem 1rem;
  border-right: 1px solid var(--rule);
  position: relative;
}
.arc-node:last-child { border-right: none; }
.arc-node::after {
  content: '→'; position: absolute;
  right: -9px; top: 50%; transform: translateY(-50%);
  color: var(--ink4); font-size: 0.8rem; z-index: 1;
}
.arc-node:last-child::after { display: none; }
.arc-phase {
  font-family: var(--mono); font-size: 0.56rem;
  letter-spacing: 0.1em; color: var(--ink4);
  text-transform: uppercase; margin-bottom: 0.35rem;
}
.arc-title { font-weight: 700; font-size: 0.85rem; margin-bottom: 0.25rem; }
.arc-time { font-family: var(--mono); font-size: 0.62rem; color: var(--red); margin-bottom: 0.5rem; }
.arc-items { display: flex; flex-direction: column; gap: 0.2rem; }
.arc-item {
  font-size: 0.74rem; color: var(--ink3); line-height: 1.5;
  display: flex; gap: 0.3rem;
}
.arc-item::before { content: '·'; color: var(--ink4); flex-shrink: 0; }

/* ── SCRIPT TIMELINE ── */
.tl { position: relative; padding-left: 2.25rem; }
.tl::before {
  content: ''; position: absolute;
  left: 0.55rem; top: 0; bottom: 0;
  width: 1px; background: var(--rule2);
}
.tl-block { position: relative; margin-bottom: 2.25rem; }
.tl-block::before {
  content: ''; position: absolute;
  left: -2.25rem; top: 0.65rem;
  width: 8px; height: 8px; border-radius: 50%;
  background: var(--bg); border: 2px solid var(--rule2);
}
.tl-block.key::before { background: var(--red); border-color: var(--red); }
.tl-block.anchor::before { background: var(--ink); border-color: var(--ink); }

.tl-meta {
  display: flex; align-items: center; gap: 0.75rem;
  margin-bottom: 0.7rem; flex-wrap: wrap;
}
.tl-time {
  font-family: var(--mono); font-size: 0.64rem;
  padding: 0.18rem 0.55rem; border-radius: 4px;
  background: var(--bg2); color: var(--ink3);
  border: 1px solid var(--rule2);
}
.tl-block.key .tl-time { background: var(--red-dim); color: var(--red); border-color: var(--red-border); }
.tl-ref { font-family: var(--mono); font-size: 0.62rem; color: var(--ink4); }
.tl-title { font-weight: 700; font-size: 0.9rem; }

.tl-card {
  background: var(--white);
  border: 1px solid var(--rule2); border-radius: 8px;
  overflow: hidden;
}
.tl-card-intent {
  padding: 0.7rem 1.1rem;
  background: var(--bg2); border-bottom: 1px solid var(--rule);
  font-size: 0.76rem; color: var(--ink3);
  display: flex; gap: 0.4rem; align-items: flex-start;
}
.tl-card-intent strong { color: var(--ink2); flex-shrink: 0; }
.tl-card-body { padding: 1.1rem; display: flex; flex-direction: column; gap: 0.45rem; }

.line-speak {
  padding: 0.7rem 0.9rem;
  background: #FFFEF5;
  border: 1px solid rgba(122,92,16,0.15);
  border-left: 3px solid var(--gold);
  border-radius: 5px;
  font-size: 0.85rem; line-height: 1.8; color: var(--ink2);
  position: relative;
}
.line-speak::after {
  content: '💬'; position: absolute;
  top: 0.6rem; right: 0.7rem;
  font-size: 0.65rem; opacity: 0.35;
}
.line-act {
  padding: 0.55rem 0.85rem;
  background: var(--teal-bg);
  border: 1px solid rgba(21,97,80,0.15);
  border-radius: 5px;
  font-size: 0.78rem; color: var(--teal);
  display: flex; gap: 0.4rem; align-items: flex-start; line-height: 1.6;
}
.line-act::before { content: '→'; flex-shrink: 0; margin-top: 0.05rem; }
.line-warn {
  padding: 0.55rem 0.85rem;
  background: var(--red-dim);
  border: 1px solid var(--red-border);
  border-radius: 5px;
  font-size: 0.78rem; color: var(--red);
  display: flex; gap: 0.4rem; align-items: flex-start; line-height: 1.6;
}
.line-warn::before { content: '⚠'; flex-shrink: 0; }
.line-tip {
  padding: 0.55rem 0.85rem;
  background: var(--blue-bg);
  border: 1px solid rgba(28,61,114,0.15);
  border-radius: 5px;
  font-size: 0.78rem; color: var(--blue);
  display: flex; gap: 0.4rem; align-items: flex-start; line-height: 1.6;
}
.line-tip::before { content: '✦'; flex-shrink: 0; }

.killer {
  margin: 0.8rem 1.1rem;
  padding: 0.8rem 1rem;
  background: var(--gold-bg);
  border-left: 3px solid var(--gold);
  border-radius: 4px;
}
.killer-lbl {
  font-family: var(--mono); font-size: 0.57rem;
  letter-spacing: 0.1em; color: var(--gold);
  text-transform: uppercase; margin-bottom: 0.25rem;
}
.killer-text {
  font-family: var(--serif); font-size: 0.92rem;
  font-weight: 600; color: var(--ink); line-height: 1.55;
}

/* ── QnA ── */
.qna { display: flex; flex-direction: column; gap: 0.85rem; }
.qna-item {
  background: var(--white);
  border: 1px solid var(--rule2); border-radius: 9px;
  overflow: hidden;
}
.qna-q {
  padding: 0.9rem 1.1rem;
  background: var(--bg2); cursor: pointer;
  display: flex; align-items: flex-start;
  justify-content: space-between; gap: 0.85rem;
  transition: background 0.15s; user-select: none;
}
.qna-q:hover { background: var(--bg3); }
.qna-q-inner { display: flex; gap: 0.65rem; align-items: flex-start; flex: 1; }
.qna-badge {
  font-family: var(--mono); font-size: 0.58rem;
  padding: 0.12rem 0.48rem; border-radius: 100px;
  white-space: nowrap; flex-shrink: 0; margin-top: 0.15rem;
}
.bd-red { background: var(--red-dim); color: var(--red); border: 1px solid var(--red-border); }
.bd-gold { background: var(--gold-bg); color: var(--gold); border: 1px solid rgba(122,92,16,0.2); }
.bd-teal { background: var(--teal-bg); color: var(--teal); border: 1px solid rgba(21,97,80,0.2); }
.qna-q-text { font-weight: 600; font-size: 0.86rem; line-height: 1.55; flex: 1; }
.qna-tog { font-size: 0.75rem; color: var(--ink4); transition: transform 0.2s; flex-shrink: 0; margin-top: 0.1rem; }
.qna-item.open .qna-tog { transform: rotate(180deg); }
.qna-a { display: none; padding: 1.1rem; border-top: 1px solid var(--rule); }
.qna-item.open .qna-a { display: block; }
.qna-intent {
  font-family: var(--mono); font-size: 0.62rem;
  color: var(--ink4); margin-bottom: 0.65rem;
  display: flex; align-items: flex-start; gap: 0.4rem;
  line-height: 1.6;
}
.qna-intent::before { content: '질문의도 —'; color: var(--red); flex-shrink: 0; }
.qna-ans { font-size: 0.85rem; color: var(--ink2); line-height: 1.85; margin-bottom: 0.8rem; }
.qna-key {
  padding: 0.7rem 0.9rem;
  background: var(--gold-bg);
  border-left: 3px solid var(--gold); border-radius: 4px;
}
.qna-key-lbl {
  font-family: var(--mono); font-size: 0.56rem;
  letter-spacing: 0.1em; color: var(--gold);
  margin-bottom: 0.2rem;
}
.qna-key-text {
  font-family: var(--serif); font-size: 0.88rem;
  font-weight: 600; color: var(--ink); line-height: 1.5;
}
.qna-follow {
  margin-top: 0.65rem; padding: 0.6rem 0.85rem;
  background: var(--blue-bg); border-radius: 4px;
  font-size: 0.77rem; color: var(--blue); line-height: 1.6;
}
.qna-follow strong { display: block; margin-bottom: 0.15rem; }

/* ── PSYCH GRID ── */
.psych-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 1.1rem; margin-bottom: 1.75rem; }
.psych-card {
  background: var(--white);
  border: 1px solid var(--rule2); border-radius: 9px;
  padding: 1.35rem;
}
.psych-hd { display: flex; align-items: center; gap: 0.65rem; margin-bottom: 0.85rem; }
.psych-ico {
  width: 38px; height: 38px; border-radius: 8px;
  display: flex; align-items: center; justify-content: center;
  font-size: 1rem; flex-shrink: 0;
}
.psych-title { font-weight: 700; font-size: 0.88rem; }
.psych-sub { font-size: 0.7rem; color: var(--ink4); font-family: var(--mono); }
.psych-body { font-size: 0.81rem; color: var(--ink2); line-height: 1.8; }
.psych-list { margin-top: 0.75rem; display: flex; flex-direction: column; gap: 0.35rem; }
.psych-li {
  font-size: 0.79rem; color: var(--ink2); line-height: 1.6;
  display: flex; gap: 0.4rem;
}
.psych-li::before { content: '·'; color: var(--red); flex-shrink: 0; }

/* ── CHECKLIST ── */
.chk-wrap {
  background: var(--white); border: 1px solid var(--rule2);
  border-radius: 9px; overflow: hidden;
}
.chk-hd {
  padding: 0.85rem 1.25rem;
  background: var(--bg2); border-bottom: 1px solid var(--rule);
  display: flex; justify-content: space-between; align-items: center;
  font-weight: 700; font-size: 0.88rem;
}
.chk-progress { font-family: var(--mono); font-size: 0.68rem; color: var(--ink4); }
.chk-progress span { color: var(--red); }
.chk-group { padding: 0.85rem 1.25rem; border-bottom: 1px solid var(--rule); }
.chk-group:last-child { border-bottom: none; }
.chk-group-lbl {
  font-family: var(--mono); font-size: 0.58rem;
  letter-spacing: 0.1em; color: var(--ink4);
  text-transform: uppercase; margin-bottom: 0.55rem;
}
.chk-item {
  display: flex; align-items: flex-start; gap: 0.6rem;
  padding: 0.38rem 0; cursor: pointer;
}
.chk-box {
  width: 17px; height: 17px; border-radius: 4px;
  border: 1.5px solid var(--rule2);
  display: flex; align-items: center; justify-content: center;
  flex-shrink: 0; margin-top: 0.12rem;
  background: var(--white); transition: all 0.15s;
}
.chk-item.done .chk-box {
  background: var(--teal); border-color: var(--teal); color: white;
}
.chk-item.done .chk-box::after { content: '✓'; font-size: 0.65rem; }
.chk-item.done .chk-text { text-decoration: line-through; color: var(--ink4); }
.chk-text { font-size: 0.83rem; color: var(--ink2); line-height: 1.55; }

/* ── CLOSE GRID ── */
.close-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 1.1rem; }
.close-card {
  background: var(--white); border: 1px solid var(--rule2);
  border-radius: 9px; padding: 1.35rem;
}
.close-card.dark {
  background: var(--ink); border-color: transparent; color: #F4F3EF;
}
.close-lbl {
  font-family: var(--mono); font-size: 0.58rem;
  letter-spacing: 0.1em; color: var(--ink4);
  text-transform: uppercase; margin-bottom: 0.5rem;
}
.close-card.dark .close-lbl { color: rgba(255,255,255,0.28); }
.close-title { font-weight: 700; font-size: 0.88rem; margin-bottom: 0.65rem; }
.close-body { font-size: 0.81rem; color: var(--ink2); line-height: 1.8; }
.close-card.dark .close-body { color: rgba(255,255,255,0.55); }

/* ── SLIDE MAP ── */
.slide-map {
  display: grid; grid-template-columns: repeat(4, 1fr);
  gap: 0.85rem; margin-bottom: 2rem;
}
.sm-card {
  background: var(--white); border: 1px solid var(--rule2);
  border-radius: 8px; padding: 1rem;
  position: relative; overflow: hidden;
  transition: transform 0.2s, border-color 0.2s;
}
.sm-card:hover { transform: translateY(-2px); border-color: var(--red-border); }
.sm-card::before {
  content: ''; position: absolute; top: 0; left: 0; right: 0;
  height: 2.5px;
}
.sm-card.phil::before { background: linear-gradient(90deg, var(--red), #D47A72); }
.sm-card.main::before { background: var(--rule2); }
.sm-card.close-s::before { background: linear-gradient(90deg, var(--ink), var(--ink3)); }
.sm-card.new::before { background: linear-gradient(90deg, var(--gold), #D4A017); }
.sm-num {
  font-family: var(--mono); font-size: 0.58rem;
  color: var(--ink4); margin-bottom: 0.3rem;
}
.sm-title { font-weight: 700; font-size: 0.8rem; margin-bottom: 0.3rem; line-height: 1.35; }
.sm-desc { font-size: 0.72rem; color: var(--ink3); line-height: 1.55; }
.sm-badge {
  display: inline-block; margin-top: 0.4rem;
  font-family: var(--mono); font-size: 0.55rem;
  padding: 0.1rem 0.42rem; border-radius: 100px;
}
.sm-badge.new-b { background: var(--gold-bg); color: var(--gold); }
.sm-badge.key-b { background: var(--red-dim); color: var(--red); }

/* ── TABLE ── */
.tbl { width: 100%; border-collapse: collapse; font-size: 0.82rem; }
.tbl th {
  text-align: left; padding: 0.6rem 0.9rem;
  font-family: var(--mono); font-size: 0.6rem;
  letter-spacing: 0.08em; color: var(--ink4);
  text-transform: uppercase; background: var(--bg2);
  border-bottom: 1px solid var(--rule2);
}
.tbl td {
  padding: 0.8rem 0.9rem; border-bottom: 1px solid var(--rule);
  color: var(--ink2); line-height: 1.65; vertical-align: top;
}
.tbl tr:last-child td { border-bottom: none; }
.tbl td:first-child { font-weight: 600; color: var(--ink); }

/* ── INNER BOX ── */
.inner-box {
  background: var(--bg2); border: 1px solid var(--rule2);
  border-radius: 8px; padding: 1.25rem 1.5rem;
  margin-bottom: 1.5rem;
}
.inner-box-lbl {
  font-family: var(--mono); font-size: 0.58rem;
  letter-spacing: 0.1em; color: var(--ink4);
  text-transform: uppercase; margin-bottom: 0.6rem;
}

/* ── RESPONSIVE ── */
@media (max-width: 860px) {
  .sidebar { display: none; }
  .main { margin-left: 0; }
  .body { padding: 0 1.25rem 4rem; }
  .hero { padding: 2rem 1.25rem; }
  .psych-grid, .close-grid { grid-template-columns: 1fr; }
  .slide-map { grid-template-columns: repeat(2, 1fr); }
  .arc { flex-direction: column; }
  .arc-node::after { display: none; }
  .arc-node { border-right: none; border-bottom: 1px solid var(--rule); }
}

@keyframes up { from { opacity:0; transform:translateY(10px); } to { opacity:1; transform:none; } }
.sec { animation: up 0.35s ease both; }
</style>
</head>
<body>

