// QnA
function toggleQ(el) { el.parentElement.classList.toggle('open'); }

// Checklist
function toggleChk(el) {
  el.classList.toggle('done');
  document.getElementById('chkCount').textContent =
    document.querySelectorAll('.chk-item.done').length;
}

// Timer
let sec = 0, iv = null, running = false;
function toggleTimer() {
  if (running) {
    clearInterval(iv); running = false;
    document.getElementById('btnStart').textContent = '재개';
    document.getElementById('btnStart').classList.remove('on');
  } else {
    iv = setInterval(() => {
      sec++;
      const d = document.getElementById('timerNum');
      d.textContent = pad(Math.floor(sec/60)) + ':' + pad(sec%60);
      d.className = 'sb-timer-num' + (sec > 1680 ? ' over' : sec > 1440 ? ' warn' : '');
    }, 1000);
    running = true;
    document.getElementById('btnStart').textContent = '일시정지';
    document.getElementById('btnStart').classList.add('on');
  }
}
function resetTimer() {
  clearInterval(iv); running = false; sec = 0;
  document.getElementById('timerNum').textContent = '00:00';
  document.getElementById('timerNum').className = 'sb-timer-num';
  document.getElementById('btnStart').textContent = '시작';
  document.getElementById('btnStart').classList.remove('on');
}
function pad(n) { return String(n).padStart(2, '0'); }

// Active nav
const secs = document.querySelectorAll('.sec');
const links = document.querySelectorAll('.sb-link');
window.addEventListener('scroll', () => {
  let cur = '';
  secs.forEach(s => { if (window.scrollY >= s.offsetTop - 130) cur = s.id; });
  links.forEach(l => l.classList.toggle('active', l.getAttribute('href') === '#' + cur));
});
</script>
