{"language": "html", "code": "<!DOCTYPE html>
<html lang="ko">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>EX Intelligence · 피칭 가이드 Final</title>
<link href="https://fonts.googleapis.com/css2?family=Noto+Serif+KR:wght@400;600;700;900&family=Noto+Sans+KR:wght@300;400;500;700&family=DM+Mono:ital,wght@0,300;0,400;0,500;1,300&display=swap" rel="stylesheet">
<style>
/* ── RESET & BASE ── */
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
html { scroll-behavior: smooth; font-size: 15px; }
body {
  font-family: 'Noto Sans KR', sans-serif;
  background: #F9F8F4;
  color: #1C1C24;
  line-height: 1.75;
  overflow-x: hidden;
}

/* ── TOKENS ── */
:root {
  --ink:      #1C1C24;
  --ink2:     #363645;
  --ink3:     #62626E;
  --ink4:     #9A9AA8;
  --cream:    #F9F8F4;
  --cream2:   #F2F0EA;
  --cream3:   #E8E5DD;
  --white:    #FFFFFF;
  --red:      #B5201A;
  --red-soft: #F5E8E7;
  --gold:     #7C5A0E;
  --gold-soft:#F7EFDA;
  --teal:     #145F50;
  --teal-soft:#DCF0EB;
  --navy:     #1A2744;
  --navy-soft:#E2E7F3;
  --rule:     rgba(28,28,36,0.10);
  --rule2:    rgba(28,28,36,0.18);
  --serif:    'Noto Serif KR', serif;
  --sans:     'Noto Sans KR', sans-serif;
  --mono:     'DM Mono', monospace;
  --shadow-sm: 0 1px 8px rgba(28,28,36,0.06);
  --shadow:   0 4px 24px rgba(28,28,36,0.08);
}

/* ── PRINT BAR (top) ── */
.print-bar {
  position: fixed; top: 0; left: 0; right: 0; z-index: 200;
  height: 52px;
  background: var(--ink);
  display: flex; align-items: center; justify-content: space-between;
  padding: 0 2rem;
}
.print-bar-brand {
  font-family: var(--mono); font-size: 0.62rem;
  letter-spacing: 0.14em; color: rgba(255,255,255,0.4);
  text-transform: uppercase;
}
.print-bar-brand span { color: var(--red); }
.print-bar-nav {
  display: flex; gap: 0.2rem;
}
.print-bar-nav a {
  font-family: var(--mono); font-size: 0.62rem;
  letter-spacing: 0.06em; color: rgba(255,255,255,0.38);
  text-decoration: none; padding: 0.3rem 0.7rem; border-radius: 3px;
  transition: all 0.15s;
}
.print-bar-nav a:hover { color: #FFF; background: rgba(255,255,255,0.1); }
.print-bar-nav a.on { color: rgba(255,255,255,0.85); }
.print-bar-timer {
  display: flex; align-items: center; gap: 0.75rem;
}
.timer-disp {
  font-family: var(--mono); font-size: 1rem; font-weight: 500;
  color: #FFF; letter-spacing: 0.08em; min-width: 52px;
  transition: color 0.3s;
}
.timer-disp.w { color: #F0A060; }
.timer-disp.o { color: #D44; }
.timer-btns { display: flex; gap: 0.3rem; }
.timer-btns button {
  font-family: var(--mono); font-size: 0.6rem;
  padding: 0.25rem 0.55rem; border-radius: 3px;
  background: rgba(255,255,255,0.1);
  border: 1px solid rgba(255,255,255,0.15);
  color: rgba(255,255,255,0.55); cursor: pointer; transition: all 0.15s;
}
.timer-btns button:hover { background: rgba(255,255,255,0.2); color: #FFF; }
.timer-btns button.on { color: #F0A060; border-color: rgba(240,160,96,0.4); }

/* ── PAGE WRAPPER ── */
.page { margin-top: 52px; }

/* ── MASTHEAD ── */
.masthead {
  background: var(--ink);
  padding: 5rem 0 4rem;
  position: relative; overflow: hidden;
}
.masthead::before {
  content: '';
  position: absolute; inset: 0;
  background: radial-gradient(ellipse 50% 100% at 85% 50%, rgba(181,32,26,0.14) 0%, transparent 60%);
}
.masthead-inner {
  max-width: 860px; margin: 0 auto; padding: 0 3rem;
  position: relative; z-index: 1;
}
.mh-kicker {
  font-family: var(--mono); font-size: 0.6rem;
  letter-spacing: 0.2em; color: var(--red);
  text-transform: uppercase; margin-bottom: 1.5rem;
  display: flex; align-items: center; gap: 0.75rem;
}
.mh-kicker::after { content: ''; flex: 0 0 32px; height: 1px; background: var(--red); }
.mh-h1 {
  font-family: var(--serif); font-size: clamp(2rem, 4vw, 3rem);
  font-weight: 900; color: #F9F8F4; line-height: 1.18;
  letter-spacing: -0.03em; margin-bottom: 1.25rem;
}
.mh-h1 em { color: #D47A72; font-style: normal; }
.mh-deck {
  font-size: 0.92rem; color: rgba(255,255,255,0.42);
  max-width: 560px; line-height: 1.9; margin-bottom: 2.5rem;
}
.mh-meta {
  display: flex; gap: 0; flex-wrap: wrap;
  border-top: 1px solid rgba(255,255,255,0.08);
  padding-top: 1.5rem;
}
.mh-meta-item {
  padding: 0 2rem 0 0; margin-right: 2rem;
  border-right: 1px solid rgba(255,255,255,0.08);
  display: flex; flex-direction: column; gap: 0.15rem;
}
.mh-meta-item:last-child { border-right: none; }
.mh-meta-lbl {
  font-family: var(--mono); font-size: 0.55rem;
  letter-spacing: 0.12em; color: rgba(255,255,255,0.22);
  text-transform: uppercase;
}
.mh-meta-val { font-size: 0.82rem; color: rgba(255,255,255,0.6); }

/* ── MAIN CONTENT ── */
.content-wrap {
  max-width: 860px; margin: 0 auto; padding: 0 3rem 6rem;
}

/* ── CHAPTER ── */
.chapter {
  margin-top: 4.5rem;
  padding-top: 4.5rem;
  border-top: 2px solid var(--ink);
}
.chapter:first-of-type { border-top: none; margin-top: 3rem; }

.ch-num {
  font-family: var(--mono); font-size: 0.58rem;
  letter-spacing: 0.18em; color: var(--ink4);
  text-transform: uppercase; margin-bottom: 0.5rem;
  display: flex; align-items: center; gap: 0.5rem;
}
.ch-num::before { content: ''; width: 14px; height: 1px; background: var(--red); }
.ch-h2 {
  font-family: var(--serif); font-size: clamp(1.5rem, 2.8vw, 2rem);
  font-weight: 900; letter-spacing: -0.03em;
  line-height: 1.2; margin-bottom: 0.6rem;
}
.ch-lead {
  font-size: 0.9rem; color: var(--ink3);
  max-width: 620px; line-height: 1.9; margin-bottom: 2.5rem;
  border-left: 3px solid var(--cream3);
  padding-left: 1rem;
}

/* ── PULL QUOTE ── */
.pull {
  margin: 2rem 0;
  padding: 1.75rem 2rem;
  background: var(--ink);
  border-radius: 4px;
  position: relative; overflow: hidden;
}
.pull::before {
  content: '';
  position: absolute; left: 0; top: 0; bottom: 0; width: 4px;
  background: var(--red);
}
.pull-lbl {
  font-family: var(--mono); font-size: 0.55rem;
  letter-spacing: 0.14em; color: var(--red);
  text-transform: uppercase; margin-bottom: 0.6rem;
}
.pull-text {
  font-family: var(--serif); font-size: 1rem;
  font-weight: 600; color: #F9F8F4; line-height: 1.6;
}
.pull-text em { color: #D47A72; font-style: normal; }

/* ── SLIDE SEQUENCE ── */
.slide-seq {
  display: flex; flex-direction: column; gap: 0;
  border: 1px solid var(--rule2); border-radius: 6px;
  overflow: hidden; margin-bottom: 2.5rem;
}
.slide-row {
  display: grid; grid-template-columns: 2.2rem 5.5rem 1fr auto;
  align-items: start; gap: 1rem;
  padding: 1rem 1.25rem;
  border-bottom: 1px solid var(--rule);
  background: var(--white);
  transition: background 0.15s;
}
.slide-row:last-child { border-bottom: none; }
.slide-row:hover { background: var(--cream2); }
.slide-row.new-slide { background: var(--gold-soft); }
.slide-row.key-slide { background: var(--navy-soft); }
.slide-num {
  font-family: var(--mono); font-size: 0.62rem;
  color: var(--ink4); padding-top: 0.1rem;
}
.slide-tag {
  font-family: var(--mono); font-size: 0.58rem;
  padding: 0.15rem 0.5rem; border-radius: 100px;
  white-space: nowrap; align-self: flex-start; margin-top: 0.1rem;
}
.tag-new { background: var(--gold-soft); color: var(--gold); border: 1px solid rgba(124,90,14,0.2); }
.tag-key { background: var(--navy-soft); color: var(--navy); border: 1px solid rgba(26,39,68,0.2); }
.tag-plain { background: var(--cream2); color: var(--ink4); border: 1px solid var(--rule); }
.tag-appendix { background: var(--cream3); color: var(--ink3); border: 1px solid var(--rule2); }
.slide-info { }
.slide-title { font-weight: 700; font-size: 0.88rem; margin-bottom: 0.2rem; }
.slide-desc { font-size: 0.79rem; color: var(--ink3); line-height: 1.55; }
.slide-time {
  font-family: var(--mono); font-size: 0.62rem;
  color: var(--red); white-space: nowrap; padding-top: 0.1rem;
}

/* ── SCRIPT BLOCKS ── */
.script-stack { display: flex; flex-direction: column; gap: 2rem; }

.sb {
  display: grid;
  grid-template-columns: 4px 1fr;
  gap: 0 1.25rem;
}
.sb-bar {
  border-radius: 4px;
  align-self: stretch;
}
.sb.key .sb-bar   { background: var(--red); }
.sb.mid .sb-bar   { background: var(--ink3); }
.sb.close .sb-bar { background: var(--ink); }

.sb-inner { }
.sb-head {
  display: flex; align-items: center; gap: 0.75rem;
  margin-bottom: 0.9rem; flex-wrap: wrap;
}
.sb-time {
  font-family: var(--mono); font-size: 0.62rem;
  padding: 0.15rem 0.55rem; border-radius: 3px;
  background: var(--cream3); color: var(--ink3);
  border: 1px solid var(--rule2);
}
.sb.key .sb-time { background: var(--red-soft); color: var(--red); }
.sb.close .sb-time { background: var(--ink); color: rgba(255,255,255,0.6); }
.sb-slide-ref {
  font-family: var(--mono); font-size: 0.6rem; color: var(--ink4);
}
.sb-title { font-weight: 700; font-size: 0.92rem; }

.sb-card {
  background: var(--white); border: 1px solid var(--rule2);
  border-radius: 5px; overflow: hidden;
}
.sb-card-intent {
  padding: 0.65rem 1rem;
  background: var(--cream2); border-bottom: 1px solid var(--rule);
  font-size: 0.76rem; color: var(--ink3);
  display: flex; gap: 0.4rem;
}
.sb-card-intent b { color: var(--ink2); flex-shrink: 0; }
.sb-card-body { padding: 0.9rem 1rem; display: flex; flex-direction: column; gap: 0.4rem; }

/* line types */
.ln {
  padding: 0.65rem 0.9rem;
  border-radius: 4px; font-size: 0.85rem; line-height: 1.8;
  display: flex; gap: 0.45rem; align-items: flex-start;
}
.ln-speak {
  background: #FEFEF8;
  border: 1px solid rgba(124,90,14,0.14);
  border-left: 3px solid var(--gold);
  color: var(--ink2);
  position: relative;
}
.ln-speak::after {
  content: '💬'; position: absolute; top: 0.55rem; right: 0.75rem;
  font-size: 0.6rem; opacity: 0.3;
}
.ln-act {
  background: var(--teal-soft);
  border: 1px solid rgba(20,95,80,0.14);
  font-size: 0.78rem; color: var(--teal);
}
.ln-act::before { content: '→'; flex-shrink: 0; font-weight: 700; margin-top: 0.05rem; }
.ln-warn {
  background: var(--red-soft);
  border: 1px solid rgba(181,32,26,0.15);
  font-size: 0.78rem; color: var(--red);
}
.ln-warn::before { content: '⚠'; flex-shrink: 0; margin-top: 0.05rem; }
.ln-tip {
  background: var(--navy-soft);
  border: 1px solid rgba(26,39,68,0.12);
  font-size: 0.78rem; color: var(--navy);
}
.ln-tip::before { content: '✦'; flex-shrink: 0; margin-top: 0.05rem; }

/* killer phrase */
.kp {
  margin: 0.6rem 0;
  padding: 0.8rem 1rem;
  background: var(--gold-soft); border-left: 3px solid var(--gold); border-radius: 3px;
}
.kp-lbl {
  font-family: var(--mono); font-size: 0.54rem;
  letter-spacing: 0.1em; color: var(--gold); text-transform: uppercase;
  margin-bottom: 0.22rem;
}
.kp-text {
  font-family: var(--serif); font-size: 0.95rem;
  font-weight: 700; color: var(--ink); line-height: 1.5;
}

/* ── QnA ── */
.qna-grid { display: flex; flex-direction: column; gap: 0.7rem; }
.qa {
  border: 1px solid var(--rule2); border-radius: 5px;
  background: var(--white); overflow: hidden;
}
.qa-q {
  padding: 0.85rem 1.1rem;
  background: var(--cream2);
  display: flex; align-items: flex-start;
  justify-content: space-between; gap: 0.85rem;
  cursor: pointer; transition: background 0.15s; user-select: none;
}
.qa-q:hover { background: var(--cream3); }
.qa-q-inner { display: flex; gap: 0.6rem; align-items: flex-start; flex: 1; }
.qa-badge {
  font-family: var(--mono); font-size: 0.56rem;
  padding: 0.12rem 0.44rem; border-radius: 100px;
  white-space: nowrap; flex-shrink: 0; margin-top: 0.1rem;
}
.bd-r { background: var(--red-soft); color: var(--red); border: 1px solid rgba(181,32,26,0.2); }
.bd-g { background: var(--gold-soft); color: var(--gold); border: 1px solid rgba(124,90,14,0.2); }
.bd-t { background: var(--teal-soft); color: var(--teal); border: 1px solid rgba(20,95,80,0.2); }
.qa-q-text { font-weight: 600; font-size: 0.86rem; line-height: 1.5; flex: 1; }
.qa-tog { color: var(--ink4); font-size: 0.72rem; transition: transform 0.2s; flex-shrink: 0; margin-top: 0.2rem; }
.qa.open .qa-tog { transform: rotate(180deg); }
.qa-a { display: none; padding: 1rem 1.1rem; border-top: 1px solid var(--rule); }
.qa.open .qa-a { display: block; }
.qa-intent {
  font-family: var(--mono); font-size: 0.6rem; color: var(--ink4);
  margin-bottom: 0.65rem; display: flex; gap: 0.4rem; align-items: flex-start;
}
.qa-intent::before { content: '질문 의도 —'; color: var(--red); flex-shrink: 0; }
.qa-ans { font-size: 0.85rem; color: var(--ink2); line-height: 1.85; margin-bottom: 0.75rem; }
.qa-key {
  padding: 0.7rem 0.9rem;
  background: var(--gold-soft); border-left: 3px solid var(--gold); border-radius: 3px;
}
.qa-key-lbl { font-family: var(--mono); font-size: 0.54rem; letter-spacing: 0.1em; color: var(--gold); margin-bottom: 0.2rem; }
.qa-key-text { font-family: var(--serif); font-size: 0.9rem; font-weight: 700; color: var(--ink); line-height: 1.5; }
.qa-follow {
  margin-top: 0.6rem; padding: 0.6rem 0.85rem;
  background: var(--navy-soft); border-radius: 3px;
  font-size: 0.77rem; color: var(--navy); line-height: 1.6;
}
.qa-follow b { display: block; margin-bottom: 0.15rem; }

/* ── PSYCH CARDS ── */
.psych-2col {
  display: grid; grid-template-columns: 1fr 1fr; gap: 1rem;
  margin-bottom: 2rem;
}
.pc {
  background: var(--white); border: 1px solid var(--rule2); border-radius: 5px;
  padding: 1.35rem;
}
.pc-hd { display: flex; align-items: center; gap: 0.65rem; margin-bottom: 0.85rem; }
.pc-ico {
  width: 36px; height: 36px; border-radius: 7px;
  display: flex; align-items: center; justify-content: center;
  font-size: 0.95rem; flex-shrink: 0;
}
.pc-title { font-weight: 700; font-size: 0.88rem; }
.pc-sub { font-family: var(--mono); font-size: 0.62rem; color: var(--ink4); }
.pc-body { font-size: 0.82rem; color: var(--ink2); line-height: 1.8; }
.pc-pts { margin-top: 0.75rem; display: flex; flex-direction: column; gap: 0.35rem; }
.pc-pt {
  font-size: 0.79rem; color: var(--ink2); line-height: 1.6;
  display: flex; gap: 0.4rem;
}
.pc-pt::before { content: '·'; color: var(--red); flex-shrink: 0; }

/* ── CHECKLIST ── */
.cl-wrap {
  background: var(--white); border: 1px solid var(--rule2); border-radius: 5px; overflow: hidden;
}
.cl-hd {
  padding: 0.8rem 1.25rem;
  background: var(--ink); color: #F9F8F4;
  display: flex; justify-content: space-between; align-items: center;
  font-weight: 700; font-size: 0.88rem;
}
.cl-prog { font-family: var(--mono); font-size: 0.68rem; color: rgba(255,255,255,0.4); }
.cl-prog span { color: #F0A060; }
.cl-group { padding: 0.8rem 1.25rem; border-bottom: 1px solid var(--rule); }
.cl-group:last-child { border-bottom: none; }
.cl-glbl {
  font-family: var(--mono); font-size: 0.56rem;
  letter-spacing: 0.1em; color: var(--ink4);
  text-transform: uppercase; margin-bottom: 0.55rem;
}
.ci {
  display: flex; align-items: flex-start; gap: 0.6rem;
  padding: 0.35rem 0; cursor: pointer;
}
.ci-box {
  width: 17px; height: 17px; border-radius: 3px;
  border: 1.5px solid var(--rule2);
  display: flex; align-items: center; justify-content: center;
  flex-shrink: 0; margin-top: 0.1rem;
  background: var(--white); transition: all 0.15s;
}
.ci.done .ci-box { background: var(--teal); border-color: var(--teal); }
.ci.done .ci-box::after { content: '✓'; font-size: 0.62rem; color: white; }
.ci.done .ci-text { text-decoration: line-through; color: var(--ink4); }
.ci-text { font-size: 0.83rem; color: var(--ink2); line-height: 1.55; }

/* ── AFTER TABLE ── */
.after-tbl {
  width: 100%; border-collapse: collapse; font-size: 0.83rem;
  margin-top: 1.5rem;
}
.after-tbl th {
  text-align: left; padding: 0.6rem 0.9rem;
  font-family: var(--mono); font-size: 0.58rem;
  letter-spacing: 0.08em; color: var(--ink4); text-transform: uppercase;
  background: var(--cream2); border-bottom: 1px solid var(--rule2);
}
.after-tbl td {
  padding: 0.78rem 0.9rem; border-bottom: 1px solid var(--rule);
  color: var(--ink2); line-height: 1.6; vertical-align: top;
}
.after-tbl tr:last-child td { border-bottom: none; }
.after-tbl td:first-child { font-weight: 600; color: var(--ink); white-space: nowrap; }

/* ── CLOSE GRID ── */
.close-2col { display: grid; grid-template-columns: 1fr 1fr; gap: 1rem; margin-bottom: 1.5rem; }
.cc {
  background: var(--white); border: 1px solid var(--rule2); border-radius: 5px; padding: 1.35rem;
}
.cc.dark { background: var(--ink); border-color: transparent; }
.cc-lbl {
  font-family: var(--mono); font-size: 0.56rem; letter-spacing: 0.1em;
  color: var(--ink4); text-transform: uppercase; margin-bottom: 0.5rem;
}
.cc.dark .cc-lbl { color: rgba(255,255,255,0.28); }
.cc-title { font-weight: 700; font-size: 0.88rem; margin-bottom: 0.6rem; }
.cc.dark .cc-title { color: #F9F8F4; }
.cc-body { font-size: 0.82rem; color: var(--ink2); line-height: 1.8; }
.cc.dark .cc-body { color: rgba(255,255,255,0.5); }

/* ── RESPONSIVE ── */
@media (max-width: 700px) {
  .content-wrap { padding: 0 1.25rem 4rem; }
  .masthead-inner { padding: 0 1.25rem; }
  .psych-2col, .close-2col { grid-template-columns: 1fr; }
  .slide-row { grid-template-columns: 2rem 1fr; }
  .slide-row .slide-tag, .slide-row .slide-time { display: none; }
  .print-bar-nav { display: none; }
}

@media print {
  .print-bar { display: none; }
  .page { margin-top: 0; }
  .chapter { page-break-before: always; }
}

/* ── ANIM ── */
@keyframes fadeUp {
  from { opacity: 0; transform: translateY(12px); }
  to { opacity: 1; transform: none; }
}
.chapter { animation: fadeUp 0.4s ease both; }
</style>
</head>
<body>

<!-- TOP BAR -->
