<script>
// ── QnA ──
function tq(el) { el.parentElement.classList.toggle('open'); }

// ── Checklist ──
function tc(el) {
  el.classList.toggle('done');
  document.getElementById('cc').textContent =
    document.querySelectorAll('.ci.done').length;
}

// ── Timer ──
let s=0, iv=null, run=false;
function tt() {
  if(run) {
    clearInterval(iv); run=false;
    document.getElementById('tbtn').textContent='재개';
    document.getElementById('tbtn').classList.remove('on');
  } else {
    iv=setInterval(()=>{
      s++;
      const d=document.getElementById('td');
      d.textContent=p(Math.floor(s/60))+':'+p(s%60);
      d.className='timer-disp'+(s>1680?' o':s>1440?' w':'');
    },1000);
    run=true;
    document.getElementById('tbtn').textContent='일시정지';
    document.getElementById('tbtn').classList.add('on');
  }
}
function tr() {
  clearInterval(iv); run=false; s=0;
  const d=document.getElementById('td');
  d.textContent='00:00'; d.className='timer-disp';
  document.getElementById('tbtn').textContent='시작';
  document.getElementById('tbtn').classList.remove('on');
}
function p(n){return String(n).padStart(2,'0');}

// ── Nav active ──
const chs=document.querySelectorAll('.chapter');
const nls=document.querySelectorAll('.print-bar-nav a');
window.addEventListener('scroll',()=>{
  let cur='';
  chs.forEach(c=>{if(window.scrollY>=c.offsetTop-120)cur=c.id;});
  nls.forEach(l=>l.classList.toggle('on',l.getAttribute('href')==='#'+cur));
});
</script>
